21055 Value *BoUpSLP::vectorizeTree(
21056     const ExtraValueToDebugLocsMap &ExternallyUsedValues,
21057     Instruction *ReductionRoot,
21058     ArrayRef<std::tuple<Value *, unsigned, bool>> VectorValuesAndScales) {
21059   // Clean Entry-to-LastInstruction table. It can be affected after scheduling,
21060   // need to rebuild it.
21061   EntryToLastInstruction.clear();
21062   // All blocks must be scheduled before any instructions are inserted.
21063   for (auto &BSIter : BlocksSchedules)
21064     scheduleBlock(*this, BSIter.second.get());
21065   // Cache last instructions for the nodes to avoid side effects, which may
21066   // appear during vectorization, like extra uses, etc.
21067   for (const std::unique_ptr<TreeEntry> &TE : VectorizableTree) {
21068     if (TE->isGather() || DeletedNodes.contains(TE.get()) ||
21069         (TE->State == TreeEntry::CombinedVectorize &&
21070          TE->CombinedOp == TreeEntry::ReducedBitcast))
21071       continue;
21072     (void)getLastInstructionInBundle(TE.get());
21073   }
21074 
21075   if (ReductionRoot)
21076     Builder.SetInsertPoint(ReductionRoot->getParent(),
21077                            ReductionRoot->getIterator());
21078   else
21079     Builder.SetInsertPoint(&F->getEntryBlock(), F->getEntryBlock().begin());
21080 
21081   // Vectorize gather operands of the nodes with the external uses only.
21082   SmallVector<std::pair<TreeEntry *, Instruction *>> GatherEntries;
21083   for (const std::unique_ptr<TreeEntry> &TE : VectorizableTree) {
21084     if (DeletedNodes.contains(TE.get()))
21085       continue;
21086     if (TE->isGather() && !TE->VectorizedValue && TE->UserTreeIndex.UserTE &&
21087         TE->UserTreeIndex.UserTE->hasState() &&
21088         TE->UserTreeIndex.UserTE->State == TreeEntry::Vectorize &&
21089         (TE->UserTreeIndex.UserTE->getOpcode() != Instruction::PHI ||
21090          TE->UserTreeIndex.UserTE->isAltShuffle()) &&
21091         !TE->UserTreeIndex.UserTE->hasCopyableElements() &&
21092         all_of(TE->UserTreeIndex.UserTE->Scalars,
21093                [](Value *V) { return isUsedOutsideBlock(V); })) {
21094       Instruction &LastInst =
21095           getLastInstructionInBundle(TE->UserTreeIndex.UserTE);
21096       GatherEntries.emplace_back(TE.get(), &LastInst);
21097     }
21098   }
21099   for (auto &Entry : GatherEntries) {
21100     IRBuilderBase::InsertPointGuard Guard(Builder);
21101     Builder.SetInsertPoint(Entry.second);
21102     Builder.SetCurrentDebugLocation(Entry.second->getDebugLoc());
21103     (void)vectorizeTree(Entry.first);
21104   }
21105   // Emit gathered loads first to emit better code for the users of those
21106   // gathered loads.
21107   for (const std::unique_ptr<TreeEntry> &TE : VectorizableTree) {
21108     if (DeletedNodes.contains(TE.get()))
21109       continue;
21110     if (GatheredLoadsEntriesFirst.has_value() &&
21111         TE->Idx >= *GatheredLoadsEntriesFirst && !TE->VectorizedValue &&
21112         (!TE->isGather() || TE->UserTreeIndex)) {
21113       assert((TE->UserTreeIndex ||
21114               (TE->getOpcode() == Instruction::Load && !TE->isGather())) &&
21115              "Expected gathered load node.");
21116       (void)vectorizeTree(TE.get());
21117     }
21118   }
21119   (void)vectorizeTree(VectorizableTree[0].get());
21120   // Run through the list of postponed gathers and emit them, replacing the temp
21121   // emitted allocas with actual vector instructions.
21122   ArrayRef<const TreeEntry *> PostponedNodes = PostponedGathers.getArrayRef();
21123   DenseMap<Value *, SmallVector<TreeEntry *>> PostponedValues;
21124   for (const TreeEntry *E : PostponedNodes) {
21125     auto *TE = const_cast<TreeEntry *>(E);
