21127     TE->VectorizedValue = nullptr;
21128     auto *UserI = cast<Instruction>(TE->UserTreeIndex.UserTE->VectorizedValue);
21129     // If user is a PHI node, its vector code have to be inserted right before
21130     // block terminator. Since the node was delayed, there were some unresolved
21131     // dependencies at the moment when stab instruction was emitted. In a case
21132     // when any of these dependencies turn out an operand of another PHI, coming
21133     // from this same block, position of a stab instruction will become invalid.
21134     // The is because source vector that supposed to feed this gather node was
21135     // inserted at the end of the block [after stab instruction]. So we need
21136     // to adjust insertion point again to the end of block.
21137     if (isa<PHINode>(UserI) ||
21138         (TE->UserTreeIndex.UserTE->hasState() &&
21139          TE->UserTreeIndex.UserTE->getOpcode() == Instruction::PHI)) {
21140       // Insert before all users.
21141       Instruction *InsertPt = PrevVec->getParent()->getTerminator();
21142       for (User *U : PrevVec->users()) {
21143         if (U == UserI)
21144           continue;
21145         auto *UI = dyn_cast<Instruction>(U);
21146         if (!UI || isa<PHINode>(UI) || UI->getParent() != InsertPt->getParent())
21147           continue;
21148         if (UI->comesBefore(InsertPt))
