21157     if (auto *VecI = dyn_cast<Instruction>(Vec);
21158         VecI && VecI->getParent() == Builder.GetInsertBlock() &&
21159         Builder.GetInsertPoint()->comesBefore(VecI))
21160       VecI->moveBeforePreserving(*Builder.GetInsertBlock(),
21161                                  Builder.GetInsertPoint());
