21163       assert(Vec->getType()->isIntOrIntVectorTy() &&
21164              PrevVec->getType()->isIntOrIntVectorTy() &&
21165              "Expected integer vector types only.");
21166       std::optional<bool> IsSigned;
21167       for (Value *V : TE->Scalars) {
21168         if (isVectorized(V)) {
21169           for (const TreeEntry *MNTE : getTreeEntries(V)) {
21170             auto It = MinBWs.find(MNTE);
21171             if (It != MinBWs.end()) {
21172               IsSigned = IsSigned.value_or(false) || It->second.second;
